import{_ as n,o as h,c as a,ag as i}from"./chunks/framework.CxZWPeXl.js";const s=JSON.parse('{"title":"Bảng điều khiển","description":"","frontmatter":{},"headers":[],"relativePath":"dashboard.md","filePath":"dashboard.md"}'),r={name:"dashboard.md"};function o(c,t,l,g,u,e){return h(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="bang-đieu-khien" tabindex="-1">Bảng điều khiển <a class="header-anchor" href="#bang-đieu-khien" aria-label="Permalink to &quot;Bảng điều khiển&quot;">​</a></h1><blockquote><p>Nắm bắt nhanh tiến độ và kết quả học tập của bạn</p></blockquote><h2 id="tong-quan-trang" tabindex="-1">Tổng quan Trang <a class="header-anchor" href="#tong-quan-trang" aria-label="Permalink to &quot;Tổng quan Trang&quot;">​</a></h2><p>Bảng điều khiển là trang chủ sau khi đăng nhập, cung cấp cái nhìn tổng quan về quá trình học tập cá nhân và các lối tắt nhanh. Trang được chia thành hai phần: <strong>Thẻ Thống kê</strong> và <strong>Lịch sử Luyện tập Gần đây</strong>. Ngoài ra, thanh điều hướng phía trên cùng cung cấp các tính năng hệ thống cốt lõi.</p><h2 id="đieu-huong-he-thong-ngay-tren-cung" tabindex="-1">Điều hướng Hệ thống Ngay trên Cùng <a class="header-anchor" href="#đieu-huong-he-thong-ngay-tren-cung" aria-label="Permalink to &quot;Điều hướng Hệ thống Ngay trên Cùng&quot;">​</a></h2><ul><li><strong>Logo/Trang chủ:</strong> Trở về Bảng điều khiển từ bất kỳ đâu.</li><li><strong>Trình chuyển đổi Ngôn ngữ:</strong> Cài đặt ngôn ngữ giao diện (hỗ trợ Tiếng Việt và Tiếng Trung Phồn thể).</li><li><strong>AI 知識助手 (Trợ lý Kiến thức AI):</strong> Mở cửa sổ công cụ hỗ trợ tư vấn viên.</li><li><strong>Hệ thống Quản lý (Admin):</strong> Dành cho quản trị viên truy cập cấu hình hệ thống.</li><li><strong>Đăng xuất:</strong> Thoát phiên làm việc.</li></ul><h2 id="khu-vuc-the-thong-ke" tabindex="-1">Khu vực Thẻ Thống kê <a class="header-anchor" href="#khu-vuc-the-thong-ke" aria-label="Permalink to &quot;Khu vực Thẻ Thống kê&quot;">​</a></h2><h3 id="bat-đau-tro-chuyen-bat-đau" tabindex="-1">Bắt đầu Trò chuyện (Bắt đầu) <a class="header-anchor" href="#bat-đau-tro-chuyen-bat-đau" aria-label="Permalink to &quot;Bắt đầu Trò chuyện (Bắt đầu)&quot;">​</a></h3><ul><li>Nút bấm nổi bật để vào trang thiết lập luyện tập và bắt đầu bài tập mới.</li></ul><h3 id="tich-luy-so-lan-thuc-hanh" tabindex="-1">Tích lũy Số lần Thực hành <a class="header-anchor" href="#tich-luy-so-lan-thuc-hanh" aria-label="Permalink to &quot;Tích lũy Số lần Thực hành&quot;">​</a></h3><ul><li>Hiển thị tổng số bài luyện tập bạn đã hoàn thành cho đến nay.</li><li>Đơn vị: <strong>Lần</strong></li></ul><h3 id="tong-thoi-gian-đoi-thoai" tabindex="-1">Tổng Thời gian Đối thoại <a class="header-anchor" href="#tong-thoi-gian-đoi-thoai" aria-label="Permalink to &quot;Tổng Thời gian Đối thoại&quot;">​</a></h3><ul><li>Hiển thị tổng thời lượng của tất cả các bài luyện tập.</li><li>Đơn vị: <strong>Giờ</strong></li></ul><h3 id="chuoi-ngay-luyen-tap-lien-tiep" tabindex="-1">Chuỗi ngày Luyện tập Liên tiếp <a class="header-anchor" href="#chuoi-ngay-luyen-tap-lien-tiep" aria-label="Permalink to &quot;Chuỗi ngày Luyện tập Liên tiếp&quot;">​</a></h3><ul><li>Hiển thị số ngày bạn luyện tập liên tiếp không ngắt quãng.</li><li>Đơn vị: <strong>Ngày</strong> (Sẽ quay về 0 nếu bỏ lỡ một ngày).</li></ul><h2 id="lich-su-luyen-tap-gan-đay" tabindex="-1">Lịch sử Luyện tập Gần đây <a class="header-anchor" href="#lich-su-luyen-tap-gan-đay" aria-label="Permalink to &quot;Lịch sử Luyện tập Gần đây&quot;">​</a></h2><p>Hiển thị 5 bài thực hành gần nhất của bạn bằng bảng dữ liệu chi tiết.</p><h3 id="loc-nhanh" tabindex="-1">Lọc Nhanh <a class="header-anchor" href="#loc-nhanh" aria-label="Permalink to &quot;Lọc Nhanh&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tùy chọn</th><th>Mô tả</th></tr></thead><tbody><tr><td>Biểu tượng Đồng hồ (Mặc định)</td><td>Hiển thị 5 bài thực hành gần nhất</td></tr><tr><td>Hôm nay</td><td>Lọc các bài thực hành của ngày hôm nay</td></tr><tr><td>Chọn ngày (YYYY-MM-DD)</td><td>Lọc các bài thực hành theo ngày cụ thể</td></tr><tr><td>Tất cả</td><td>Chuyển đến trang &quot;Lịch sử&quot; để xem toàn bộ</td></tr></tbody></table><h3 id="cot-du-lieu" tabindex="-1">Cột Dữ liệu <a class="header-anchor" href="#cot-du-lieu" aria-label="Permalink to &quot;Cột Dữ liệu&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Trường</th><th>Mô tả</th></tr></thead><tbody><tr><td>Ngày</td><td>Ngày thực hiện luyện tập</td></tr><tr><td>Tuổi</td><td>Tuổi của khách hàng mô phỏng</td></tr><tr><td>Giới tính</td><td>Giới tính khách hàng mô phỏng</td></tr><tr><td>Tên</td><td>Tên khách hàng (Có thể nhấp để xem Hồ sơ Chân dung chi tiết)</td></tr><tr><td>Nghề nghiệp</td><td>Nghề nghiệp khách hàng</td></tr><tr><td>Thu nhập</td><td>Mức thu nhập khách hàng</td></tr><tr><td>Giai đoạn đạt được</td><td>Giai đoạn bán hàng cao nhất đạt được (Kèm biểu tượng chú giải chi tiết)</td></tr><tr><td>Thời lượng</td><td>Thời lượng trò chuyện thực tế (Phút)</td></tr></tbody></table><h3 id="nut-thao-tac" tabindex="-1">Nút Thao tác <a class="header-anchor" href="#nut-thao-tac" aria-label="Permalink to &quot;Nút Thao tác&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Nút</th><th>Mô tả</th></tr></thead><tbody><tr><td>Xem Đánh giá (Biểu tượng Mắt)</td><td>Chuyển đến trang báo cáo đánh giá toàn diện</td></tr><tr><td>Làm lại (Biểu tượng Xoay vòng)</td><td>Tạo bài tập mới với y hệt thiết lập khách hàng đó</td></tr><tr><td>Tiếp tục (Biểu tượng Phát)</td><td>Tiếp tục cuộc trò chuyện bị dang dở</td></tr></tbody></table><h3 id="ho-so-chan-dung-khach-hang-persona-modal" tabindex="-1">Hồ sơ Chân dung Khách hàng (Persona Modal) <a class="header-anchor" href="#ho-so-chan-dung-khach-hang-persona-modal" aria-label="Permalink to &quot;Hồ sơ Chân dung Khách hàng (Persona Modal)&quot;">​</a></h3><p>Khi bạn nhấp vào <strong>Tên</strong> của khách hàng trong bảng, một cửa sổ chi tiết sẽ hiện lên cung cấp mọi thông tin:</p><ul><li><strong>Kiểu tính cách (MBTI):</strong> Hỗ trợ bạn thấu hiểu cách ra quyết định của khách.</li><li><strong>Thông tin Gia đình &amp; Học vấn:</strong> Tình trạng hôn nhân, trình độ học vấn.</li><li><strong>Mối quan hệ:</strong> Quan hệ hiện tại giữa khách và Tư vấn viên.</li><li><strong>Nút &quot;Thử lại với vai trò này&quot;:</strong> Bắt đầu ngay bài tập với chân dung chi tiết này.</li></ul><hr><h2 id="buoc-tiep-theo" tabindex="-1">Bước tiếp theo <a class="header-anchor" href="#buoc-tiep-theo" aria-label="Permalink to &quot;Bước tiếp theo&quot;">​</a></h2><ul><li>Bắt đầu <a href="./practice.html">Thực hành</a></li><li>Hiểu nội dung <a href="./evaluation.html">Báo cáo đánh giá</a></li><li>Xem <a href="./history.html">Lịch sử</a> đầy đủ</li></ul>',29)])])}const b=n(r,[["render",o]]);export{s as __pageData,b as default};
